#!/usr/bin/env node
// guard-sensitive.mjs — PreToolUse hook for the FWBB project.
//
// WHY: AGENTS.md forbids hand-editing several classes of files. This hook makes
// that rule deterministic instead of relying on the model to remember it:
//   - `.env*` files: never edit credential/secret files (AGENTS.md "Editing" /
//     "Never edit .env* or credential files").
//   - `src/db/migrations/` DDL: generated by drizzle-kit, never hand-edited
//     (AGENTS.md schema discipline — migrations are DDL-only, generated).
//   - `pnpm-lock.yaml`: lockfile is managed by the package manager, not by hand.
//   - the fund-ledger CSV exported into `.claude/` (filename contains "FWBB",
//     ends in `.csv`): real money records, not an editable source file.
//
// BLOCK SEMANTICS: print a human-readable reason to stderr and exit(2) so Claude
// Code blocks the tool call. Allowed paths exit(0). On ANY error we exit(0) —
// a broken hook must never block legitimate work.
//
// The matcher in settings.json should scope this to Edit|Write only, so
// drizzle-kit (which runs via Bash) can still generate migration files.

function readStdin() {
  return new Promise((resolve) => {
    let data = "";
    process.stdin.setEncoding("utf8");
    process.stdin.on("data", (chunk) => {
      data += chunk;
    });
    process.stdin.on("end", () => resolve(data));
    process.stdin.on("error", () => resolve(data));
  });
}

async function main() {
  const raw = await readStdin();

  let obj;
  try {
    obj = JSON.parse(raw);
  } catch {
    // Could not parse hook input — fail open, never block.
    process.exit(0);
  }

  const filePath = obj && obj.tool_input && obj.tool_input.file_path;
  if (typeof filePath !== "string" || filePath.length === 0) {
    // No file path to inspect — nothing to guard.
    process.exit(0);
  }

  // Normalize Windows backslashes to forward slashes, lowercase for matching.
  const norm = filePath.replace(/\\/g, "/");
  const lower = norm.toLowerCase();
  const base = lower.slice(lower.lastIndexOf("/") + 1);

  // 1) .env files: .env, .env.local, .env.production, etc. (also bare ".env").
  if (base === ".env" || base.startsWith(".env.") || /(^|\/)\.env(\.[^/]*)?$/.test(lower)) {
    process.stderr.write(
      `BLOCKED: refusing to edit "${filePath}".\n` +
        `Env / credential files must never be hand-edited (AGENTS.md). ` +
        `Update secrets through your deployment config, not by editing .env files.\n`
    );
    process.exit(2);
  }

  // 2) DB migration DDL: any path under a db/migrations/ folder.
  if (lower.includes("/db/migrations/") || lower.startsWith("db/migrations/")) {
    process.stderr.write(
      `BLOCKED: refusing to edit "${filePath}".\n` +
        `Migration files are generated by drizzle-kit and are DDL-only (AGENTS.md). ` +
        `Run the drizzle-kit generate command instead of editing migrations by hand.\n`
    );
    process.exit(2);
  }

  // 3) pnpm lockfile.
  if (base === "pnpm-lock.yaml") {
    process.stderr.write(
      `BLOCKED: refusing to edit "${filePath}".\n` +
        `pnpm-lock.yaml is managed by pnpm. Change dependencies via pnpm, then commit the regenerated lockfile.\n`
    );
    process.exit(2);
  }

  // 4) Fund ledger CSV exported into .claude/ (filename contains "FWBB", ends .csv).
  if (lower.includes("/.claude/") && base.endsWith(".csv") && base.includes("fwbb")) {
    process.stderr.write(
      `BLOCKED: refusing to edit "${filePath}".\n` +
        `This is a fund-ledger CSV holding real money records. It is not an editable source file. ` +
        `Re-export it from the source of truth instead of editing by hand.\n`
    );
    process.exit(2);
  }

  // Path is allowed.
  process.exit(0);
}

main().catch(() => {
  // Any unexpected failure — fail open so the hook never blocks real work.
  process.exit(0);
});
